+
+  start = 0;
+  while (end != std::string::npos) {
+    end = wstring.find(" ", start);
+
+    parser::pddl::tree::Param param;
+    param.name = wstring.substr(
+      start,
+      (end == std::string::npos) ? std::string::npos : end - start);
+
+    ret.push_back(param);
+
+    start = ((end > (std::string::npos - 1)) ? std::string::npos : end + 1);
+  }
